mapper.sql:
select 
from gpt_openkey t

    t.deleted = 0
     and t.id = #{q.id} 
     and t.app_key = #{q.appKey}
     and t.status = #{q.status}
     and t.model = #{q.model}

        and (t.remark like concat('%', #{q.name}, '%') or t.app_id like concat('%', #{q.name}, '%') or t.model like concat('%', #{q.name}, '%')
        or exists (select 1 from gpt_model gm where gm.model = t.model and gm.deleted = 0 and gm.name like concat('%', #{q.name}, '%')))

     and date_format(t.create_time,'%Y-%m-%d') >= #{q.startDate} 
     and date_format(t.create_time,'%Y-%m-%d') <= #{q.endDate} 
     ${q.dataScope} 

order by t.id desc

mapper.update:
update gpt_openkey t set t.used_tokens = t.used_tokens + #{usedTokens},
                         t.surplus_tokens = t.total_tokens - t.used_tokens
where t.app_key = #{appKey}
